const root = $('Website Form Lead Webhook').first().json;
const body = root.body && typeof root.body === 'object' && !Array.isArray(root.body) ? root.body : root;
const config = $('Get Config').first().json;
const rawContact = body.contact && typeof body.contact === 'object' && !Array.isArray(body.contact) ? body.contact : body;
const intake = body.intake && typeof body.intake === 'object' && !Array.isArray(body.intake) ? body.intake : {};

const pick = (obj, keys) => {
  if (!obj || typeof obj !== 'object') return '';
  for (const key of keys) {
    const value = obj[key];
    if (value !== undefined && value !== null) {
      const s = String(value).trim();
      if (s) return s;
    }
  }
  return '';
};
const normalize = (value) => {
  if (value === undefined || value === null) return '';
  if (Array.isArray(value)) {
    return value.map((item) => String(item).trim()).filter(Boolean).join(', ');
  }
  return String(value).trim();
};
const objValue = (obj, key) => (obj && typeof obj === 'object' && !Array.isArray(obj) ? obj[key] : undefined);
const objString = (obj, key) => normalize(objValue(obj, key));

const contactId = pick(body, ['contactId', 'contact_id', 'hs_object_id', 'vid', 'objectId']) || pick(root, ['contactId', 'contact_id', 'hs_object_id']);
const createDeal = body.createDeal === false || body.createDeal === 'false' ? false : true;
const tier = pick(body, ['tier']) || 'starter';
const painOverride = pick(body, ['painOverride', 'message', 'notes', 'pain']) || '';
const hubspotDealId = pick(body, ['hubspotDealId', 'dealIdFromSite']) || '';
const amountRaw = body.amount !== undefined && body.amount !== null && body.amount !== '' ? Number(body.amount) : null;
const stageBuiltin = new Set(['appointmentscheduled', 'qualifiedtobuy', 'presentationscheduled', 'decisionmakerboughtin', 'contractsent', 'closedwon', 'closedlost']);
const normalizeDealStage = (value) => {
  const s = String(value || '').trim();
  if (!s) return '';
  if (/^[0-9]+$/.test(s)) return s;
  const lc = s.toLowerCase();
  if (stageBuiltin.has(lc)) return lc;
  return '';
};
const dealStage = normalizeDealStage(body.dealStage || body.deal_stage) || String(config.hubspot?.dealStageIds?.discoveryCallRequested || '').trim() || 'qualifiedtobuy';

const email = pick(rawContact, ['email', 'Email', 'emailAddress']);
const phone = pick(rawContact, ['phone', 'Phone']);
const firstName = pick(rawContact, ['firstName', 'firstname', 'first_name']);
const lastName = pick(rawContact, ['lastName', 'lastname', 'last_name']);
const company = pick(rawContact, ['company', 'businessName', 'business', 'companyName']);
const industry = pick(rawContact, ['industry', 'niche']);
const website = pick(rawContact, ['website', 'currentSite', 'site']);
const intakePlainText = typeof body.intakePlainText === 'string' ? body.intakePlainText.trim() : '';
let intakeJson = '{}';
if (typeof body.intakeJson === 'string' && body.intakeJson.trim()) {
  intakeJson = body.intakeJson.trim();
} else {
  try {
    intakeJson = JSON.stringify(intake, null, 2);
  } catch (error) {
    intakeJson = '{}';
  }
}

const intakeContact = objValue(intake, 'contact') || {};
const goals = objValue(intake, 'goals') || {};
const design = objValue(intake, 'design') || {};
const content = objValue(intake, 'content') || {};
const budget = objValue(intake, 'budget') || {};
const research = objValue(intake, 'research') || {};

const intakeMapped = {
  website_intake_audience: objString(goals, 'audience'),
  website_intake_brand_colors: objString(design, 'brandColors'),
  website_intake_budget_notes: objString(budget, 'notes'),
  website_intake_budget_range: objString(budget, 'range'),
  website_intake_business_description: objString(intakeContact, 'bizDesc'),
  website_intake_cms: objString(content, 'cms'),
  website_intake_competitors: normalize(objValue(research, 'competitors')),
  website_intake_copywriter: objString(content, 'copywriter'),
  website_intake_design_notes: objString(design, 'designNotes'),
