  website_intake_dislike_about: objString(research, 'dislikeAbout'),
  website_intake_dont_want: objString(design, 'dontWant'),
  website_intake_features: normalize(objValue(content, 'features')),
  website_intake_final_notes: objString(research, 'finalNotes'),
  website_intake_font_style: objString(design, 'fontStyle'),
  website_intake_funding: objString(budget, 'funding'),
  website_intake_goal_detail: objString(goals, 'goalDetail'),
  website_intake_goals: normalize(objValue(goals, 'goals')),
  website_intake_hard_deadline: objString(goals, 'hardDeadline'),
  website_intake_has_logo: objString(design, 'hasLogo'),
  website_intake_has_photos: objString(design, 'hasPhotos'),
  website_intake_industry: objString(intakeContact, 'industry'),
  website_intake_inspiration_sites: normalize(objValue(research, 'inspiration')),
  website_intake_like_about: objString(research, 'likeAbout'),
  website_intake_location: objString(intakeContact, 'location'),
  website_intake_ongoing_support: objString(budget, 'ongoing'),
  website_intake_other_pages: objString(content, 'otherPages'),
